            .header("Accept-Language", "zh-CN,zh;q=0.9,en;q=0.8")
            .header("Origin", getOriginFromUrl(config.url))
            .header("Connection", "keep-alive")

        // 添加Cookie（如果提供）
        if (!config.cookies.isNullOrEmpty()) {
            requestBuilder.header("Cookie", config.cookies)
            Log.d("SegmentedDownloader", "Using custom cookies for download")
        }

        val request = requestBuilder.build()

