/**
 * 使用 B站官方 API 解析
 * 参考 bilibili-api (Kotlin): https://github.com/czp3009/bilibili-api
 *
 * API 端点：
 * - 视频信息: https://api.bilibili.com/x/web-interface/view?bvid={bvid}
 * - 播放地址: https://api.bilibili.com/x/player/playurl?bvid={bvid}&cid={cid}
 */
private suspend fun fetchBilibiliOfficialAPI(url: String): Result<VideoDownloadInfo> = withContext(Dispatchers.IO) {
    try {
        // 1. 提取 BV 号
        val bvid = extractBVID(url)
        if (bvid == null) {
            return@withContext Result.failure(Exception("无法提取BV号"))
        }
        Log.d(TAG, "BV ID: $bvid")

        // 2. 获取视频信息（获取 cid）
        val infoUrl = "https://api.bilibili.com/x/web-interface/view?bvid=$bvid"
        val infoRequest = Request.Builder()
            .url(infoUrl)
            .header("User-Agent", getUserAgent())
            .header("Referer", "https://www.bilibili.com/")
            .build()

        val infoResponse = client.newCall(infoRequest).execute()
        val infoBody = infoResponse.body?.string() ?: return@withContext Result.failure(IOException("空响应"))
        val infoJson = JSONObject(infoBody)

        if (infoJson.optInt("code", -1) != 0) {
            return@withContext Result.failure(Exception("API错误: ${infoJson.optString("message")}"))
        }

        val data = infoJson.getJSONObject("data")
        val cid = data.optLong("cid")
        val title = data.optString("title")
        val cover = data.optString("pic").replace("\\/\\\\/", "/")
        val duration = data.optInt("duration")
        val author = data.optJSONObject("owner")?.optString("name") ?: "未知UP主"

        Log.d(TAG, "Video info: $title, cid=$cid")

        // 3. 获取播放URL
        val playUrl = "https://api.bilibili.com/x/player/playurl?bvid=$bvid&cid=$cid&qn=80&fnval=16&fnver=0&fourk=1"
        val playRequest = Request.Builder()
            .url(playUrl)
            .header("User-Agent", getUserAgent())
            .header("Referer", "https://www.bilibili.com/")
            .build()

        val playResponse = client.newCall(playRequest).execute()
        val playBody = playResponse.body?.string() ?: return@withContext Result.failure(IOException("空响应"))
        val playJson = JSONObject(playBody)

        if (playJson.optInt("code", -1) != 0) {
            return@withContext Result.failure(Exception("获取播放URL失败: ${playJson.optString("message")}"))
        }

        val playData = playJson.getJSONObject("data")
        val durl = playData.optJSONArray("durl")
        val videoUrl = if (durl != null && durl.length() > 0) {
            durl.getJSONObject(0).optString("url")
        } else {
            // 尝试 DASH 格式
            playData.optJSONObject("dash")?.optJSONArray("video")?.getJSONObject(0)?.optString("baseUrl")
        }

        if (videoUrl != null) {
            return@withContext Result.success(VideoDownloadInfo(
                title = title,
                downloadUrl = videoUrl,
                cover = cover,
                duration = duration.toLong(),
                author = author
            ))
        }

        Result.failure(Exception("无法获取播放地址"))

    } catch (e: Exception) {
        Log.e(TAG, "Official API error", e)
        Result.failure(e)
    }
}

