@HiltViewModel
class HomeViewModel @Inject constructor(
    @SuppressLint("StaticFieldLeak") private val application: Application,
    private val videoRepository: VideoRepository,
    private val themeStore: ThemeStore,
    private val videoConfigStore: com.multilanglearner.data.store.VideoConfigStore,
    private val segmentedDownloader: SegmentedDownloader
) : AndroidViewModel(application) {

    private var currentBilibiliCookie: String? = null

    init {
        // 收集Cookie配置
        viewModelScope.launch {
            videoConfigStore.config.collect { config ->
                currentBilibiliCookie = config.getBilibiliCookie()
            }
        }
    }

