   323→@Composable
   324→private fun DownloadProgressCard(
   325→    task: DownloadTask,
   326→    onCancel: () -> Unit,
   327→    formatFileSize: (Long) -> String,
   328→    formatSpeed: (Long) -> String,
   329→    formatRemainingTime: (Long) -> String,
   330→    getStatusText: (DownloadStatus) -> String
   331→) {
   332→    Card(
   333→        modifier = Modifier.fillMaxWidth(),
   334→        colors = CardDefaults.cardColors(
   335→            containerColor = when (task.status) {
   336→                DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.errorContainer
   337→                else -> MaterialTheme.colorScheme.primaryContainer
   338→            }
   339→        )
   340→    ) {
   341→        Column(modifier = Modifier.padding(16.dp)) {
   342→            // 标题和状态
   343→            Row(
   344→                modifier = Modifier.fillMaxWidth(),
   345→                horizontalArrangement = Arrangement.SpaceBetween,
   346→                verticalAlignment = Alignment.CenterVertically
   347→            ) {
   348→                Column(Modifier.weight(1f)) {
   349→                    Text(
   350→                        task.title,
   351→                        style = MaterialTheme.typography.titleSmall,
   352→                        maxLines = 1,
   353→                        overflow = TextOverflow.Ellipsis
   354→                    )
   355→                    Text(
   356→                        getStatusText(task.status),
   357→                        style = MaterialTheme.typography.bodySmall,
   358→                        color = when (task.status) {
   359→                            DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.error
   360→                            else -> MaterialTheme.colorScheme.onPrimaryContainer
   361→                        }
   362→                    )
   363→                }
   364→
   365→                // 取消按钮
   366→                if (task.status == DownloadStatus.DOWNLOADING || task.status == DownloadStatus.FETCHING_INFO) {
   367→                    IconButton(onClick = onCancel) {
   368→                        Icon(Icons.Default.Close, "取消", tint = MaterialTheme.colorScheme.error)
   369→                    }
   370→                }
   371→            }
   372→
   373→            Spacer(Modifier.height(12.dp))
   374→
   375→            // 进度条
   376→            if (task.status == DownloadStatus.DOWNLOADING) {
   377→                Column {
   378→                    Row(
   379→                        modifier = Modifier.fillMaxWidth(),
   380→                        horizontalArrangement = Arrangement.SpaceBetween
   381→                    ) {
   382→                        Text(
   383→                            "${task.progress}%",
   384→                            style = MaterialTheme.typography.bodySmall
   385→                        )
   386→                        if (task.speed > 0) {
   387→                            Text(
   388→                                formatSpeed(task.speed),
   389→                                style = MaterialTheme.typography.bodySmall,
   390→                                color = MaterialTheme.colorScheme.primary
   391→                            )
   392→                        }
   393→                    }
   394→
   395→                    Spacer(Modifier.height(4.dp))
   396→
   397→                    LinearProgressIndicator(
   398→                        progress = { task.progress / 100f },
   399→                        modifier = Modifier.fillMaxWidth(),
   400→                        color = MaterialTheme.colorScheme.primary
   401→                    )
   402→
   403→                    // 文件大小和剩余时间
   404→                    if (task.totalBytes > 0) {
   405→                        Spacer(Modifier.height(4.dp))
   406→                        Row(
   407→                            modifier = Modifier.fillMaxWidth(),
   408→                            horizontalArrangement = Arrangement.SpaceBetween
   409→                        ) {
   410→                            Text(
   411→                                "${formatFileSize(task.bytesDownloaded)} / ${formatFileSize(task.totalBytes)}",
   412→                                style = MaterialTheme.typography.bodySmall,
   413→                                color = MaterialTheme.colorScheme.onPrimaryContainer
   414→                            )
   415→                            if (task.remainingTime > 0 && task.speed > 0) {
   416→                                Text(
   417→                                    "剩余 ${formatRemainingTime(task.remainingTime)}",
   418→                                    style = MaterialTheme.typography.bodySmall,
   419→                                    color = MaterialTheme.colorScheme.onPrimaryContainer
   420→                                )
   421→                            }
   422→                        }
   423→                    }
   424→                }
   425→            } else if (task.status == DownloadStatus.FETCHING_INFO) {
   426→                Row(
   427→                    modifier = Modifier.fillMaxWidth(),
   428→                    verticalAlignment = Alignment.CenterVertically
   429→                ) {
   430→                    CircularProgressIndicator(
   431→                        modifier = Modifier.size(20.dp),
   432→                        strokeWidth = 2.dp
   433→                    )
   434→                    Spacer(Modifier.width(8.dp))
   435→                    Text(
   436→                        "正在解析视频信息...",
   437→                        style = MaterialTheme.typography.bodySmall,
   438→                        color = MaterialTheme.colorScheme.onPrimaryContainer
   439→                    )
   440→                }
   441→            } else if (task.status == DownloadStatus.FAILED) {
   442→                Row(
   443→                    modifier = Modifier.fillMaxWidth(),
   444→                    verticalAlignment = Alignment.CenterVertically
   445→                ) {
   446→                    Icon(
   447→                        Icons.Default.Error,
   448→                        contentDescription = null,
   449→                        tint = MaterialTheme.colorScheme.error,
   450→                        modifier = Modifier.size(20.dp)
   451→                    )
   452→                    Spacer(Modifier.width(8.dp))
   453→                    Text(
   454→                        task.errorMessage ?: "下载失败",
   455→                        style = MaterialTheme.typography.bodySmall,
   456→                        color = MaterialTheme.colorScheme.error
   457→                    )
   458→                }
   459→            } else if (task.status == DownloadStatus.COMPLETED) {
   460→                Row(
   461→                    modifier = Modifier.fillMaxWidth(),
   462→                    verticalAlignment = Alignment.CenterVertically
   463→                ) {
   464→                    Icon(
   465→                        Icons.Default.CheckCircle,
   466→                        contentDescription = null,
   467→                        tint = MaterialTheme.colorScheme.primary,
   468→                        modifier = Modifier.size(20.dp)
   469→                    )
   470→                    Spacer(Modifier.width(8.dp))
   471→                    Text(
   472→                        "下载完成",
   473→                        style = MaterialTheme.typography.bodySmall,
   474→                        color = MaterialTheme.colorScheme.primary
   475→                    )
   476→                }
   477→            }
   478→        }
   479→    }
   480→}
